SELECT JSON_EXTRACT_INDEX(commit, '$.collection', 'STRING', 'null') AS event, count(*) AS count FROM bluesky GROUP BY event ORDER BY count DESC;
SELECT JSON_EXTRACT_INDEX(commit, '$.collection', 'STRING', 'null') AS event, count(*) AS count, COUNT(DISTINCT did) AS users FROM bluesky WHERE kind = 'commit' AND JSON_EXTRACT_INDEX(commit, '$.operation', 'STRING', 'null') = 'create' GROUP BY event ORDER BY count DESC;
SELECT JSON_EXTRACT_INDEX(commit, '$.collection', 'STRING', 'null') AS event, MOD(time_us / 3600000000, 24) AS hour_of_day, count(*) AS count FROM bluesky WHERE kind = 'commit' AND JSON_EXTRACT_INDEX(commit, '$.operation', 'STRING', 'null') = 'create' AND JSON_EXTRACT_INDEX(commit, '$.collection', 'STRING', 'null') IN ('app.bsky.feed.post', 'app.bsky.feed.repost', 'app.bsky.feed.like') GROUP BY event, hour_of_day ORDER BY hour_of_day, event;
SELECT did AS user_id, MIN(time_us) AS first_post_ts FROM bluesky WHERE kind = 'commit' AND JSON_EXTRACT_INDEX(commit, '$.operation', 'STRING', 'null') = 'create' AND JSON_EXTRACT_INDEX(commit, '$.collection', 'STRING', 'null') = 'app.bsky.feed.post' GROUP BY user_id ORDER BY first_post_ts ASC LIMIT 3;
SELECT did AS user_id, MAX(time_us) - MIN(time_us) AS activity_span FROM bluesky WHERE kind = 'commit' AND JSON_EXTRACT_INDEX(commit, '$.operation', 'STRING', 'null') = 'create' AND JSON_EXTRACT_INDEX(commit, '$.collection', 'STRING', 'null') = 'app.bsky.feed.post' GROUP BY user_id ORDER BY activity_span DESC LIMIT 3;
